import requests
from urllib.parse import urlparse
import ipaddress

def fetch_url(url):
    # Allowlist expected hosts or domains
    allowed_hosts = ["example.com", "api.example.com"]
    
    # Resolve and reject loopback, link-local, multicast, and private IP destinations
    parsed_url = urlparse(url)
    if parsed_url.netloc.startswith("localhost") or ipaddress.ip_address(parsed_url.netloc).is_private:
        return "Invalid URL: Private IP address"
        
    # Check if the host is in the allowlist
    if parsed_url.netloc not in allowed_hosts:
        return "Invalid URL: Host not in allowlist"
    
    try:
        response = requests.get(url, allow_redirects=False)
        response.raise_for_status()
        return response.text
    except requests.RequestException as e:
        return f"Error fetching URL: {e}"